"use strict";(self.webpackChunksysanalyst_kb=self.webpackChunksysanalyst_kb||[]).push([["89347"],{50014(i){i.exports=JSON.parse('{"tag":{"label":"api","permalink":"/sysanalyst-kb.github.io/docs/tags/api","allTagsPath":"/sysanalyst-kb.github.io/docs/tags","count":11,"items":[{"id":"data/api-first-design","title":"API-first design","description":"API-first \u2014 \u044D\u0442\u043E \u043F\u043E\u0434\u0445\u043E\u0434 \u043A \u0440\u0430\u0437\u0440\u0430\u0431\u043E\u0442\u043A\u0435, \u043F\u0440\u0438 \u043A\u043E\u0442\u043E\u0440\u043E\u043C API \u043F\u0440\u043E\u0435\u043A\u0442\u0438\u0440\u0443\u0435\u0442\u0441\u044F \u0438 \u0441\u043F\u0435\u0446\u0438\u0444\u0438\u0446\u0438\u0440\u0443\u0435\u0442\u0441\u044F \u0434\u043E \u043D\u0430\u0447\u0430\u043B\u0430 \u043D\u0430\u043F\u0438\u0441\u0430\u043D\u0438\u044F \u043A\u043E\u0434\u0430. API \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u043A\u043E\u043D\u0442\u0440\u0430\u043A\u0442\u043E\u043C, \u0432\u043E\u043A\u0440\u0443\u0433 \u043A\u043E\u0442\u043E\u0440\u043E\u0433\u043E \u0441\u0442\u0440\u043E\u044F\u0442\u0441\u044F \u0438 \u0444\u0440\u043E\u043D\u0442\u0435\u043D\u0434, \u0438 \u0431\u044D\u043A\u0435\u043D\u0434.","permalink":"/sysanalyst-kb.github.io/docs/data/api-first-design"},{"id":"specialization/fintech-open-banking","title":"Open Banking / PSD2 \u2014 API, SCA, Berlin Group","description":"Open Banking \u2014 \u0442\u0440\u0435\u0431\u043E\u0432\u0430\u043D\u0438\u0435 \u0440\u0435\u0433\u0443\u043B\u044F\u0442\u043E\u0440\u0430 (PSD2 \u0432 EU, Open Banking Standard \u0432 UK) \u0437\u0430\u0441\u0442\u0430\u0432\u0438\u0442\u044C \u0431\u0430\u043D\u043A\u0438 \u043E\u0442\u043A\u0440\u044B\u0442\u044C API \u0434\u043B\u044F \u0442\u0440\u0435\u0442\u044C\u0438\u0445 \u0441\u0442\u043E\u0440\u043E\u043D. \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u0434\u043E\u043B\u0436\u0435\u043D \u043F\u043E\u043D\u0438\u043C\u0430\u0442\u044C: \u043A\u0430\u043A\u0438\u0435 \u0442\u0438\u043F\u044B API \u043D\u0443\u0436\u043D\u044B (AISP, PISP), \u043A\u0430\u043A \u0440\u0430\u0431\u043E\u0442\u0430\u0435\u0442 consent management, \u0447\u0442\u043E \u0442\u0430\u043A\u043E\u0435 SCA (\u0441\u0438\u043B\u044C\u043D\u0430\u044F \u0430\u0443\u0442\u0435\u043D\u0442\u0438\u0444\u0438\u043A\u0430\u0446\u0438\u044F), \u0438 \u043A\u0430\u043A\u0438\u0435 \u0441\u0442\u0430\u043D\u0434\u0430\u0440\u0442\u044B \u043E\u043F\u0438\u0441\u044B\u0432\u0430\u044E\u0442 API (Berlin Group, UK Standard, FAPI).","permalink":"/sysanalyst-kb.github.io/docs/specialization/fintech-open-banking"},{"id":"integration/api-auth","title":"\u0410\u0443\u0442\u0435\u043D\u0442\u0438\u0444\u0438\u043A\u0430\u0446\u0438\u044F \u0438 \u0430\u0432\u0442\u043E\u0440\u0438\u0437\u0430\u0446\u0438\u044F \u0432 API","description":"\u041B\u044E\u0431\u043E\u0439 API, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u0440\u0430\u0431\u043E\u0442\u0430\u0435\u0442 \u043D\u0435 \u0432 \u0438\u0437\u043E\u043B\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u043E\u0439 \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0439 \u0441\u0435\u0442\u0438, \u043D\u0443\u0436\u0434\u0430\u0435\u0442\u0441\u044F \u0432 \u0437\u0430\u0449\u0438\u0442\u0435. \u0414\u0430\u0436\u0435 \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0438\u0435 API \u043E\u0431\u044B\u0447\u043D\u043E \u0442\u0440\u0435\u0431\u0443\u044E\u0442 \u0445\u043E\u0442\u044F \u0431\u044B \u0431\u0430\u0437\u043E\u0432\u043E\u0439 \u0430\u0443\u0442\u0435\u043D\u0442\u0438\u0444\u0438\u043A\u0430\u0446\u0438\u0438, \u0447\u0442\u043E\u0431\u044B \u0437\u043D\u0430\u0442\u044C, \u043A\u0442\u043E \u0438 \u043A\u0430\u043A\u0438\u0435 \u0434\u0430\u043D\u043D\u044B\u0435 \u0437\u0430\u043F\u0440\u0430\u0448\u0438\u0432\u0430\u0435\u0442.","permalink":"/sysanalyst-kb.github.io/docs/integration/api-auth"},{"id":"integration/api-versioning","title":"\u0412\u0435\u0440\u0441\u0438\u043E\u043D\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u0435 API","description":"API \u0436\u0438\u0432\u0451\u0442 \u0434\u043E\u043B\u044C\u0448\u0435, \u0447\u0435\u043C \u043B\u044E\u0431\u0430\u044F single-page app. \u0427\u0435\u0440\u0435\u0437 \u0433\u043E\u0434 \u043F\u043E\u0441\u043B\u0435 \u0437\u0430\u043F\u0443\u0441\u043A\u0430 \u043F\u043E\u044F\u0432\u044F\u0442\u0441\u044F \u043D\u043E\u0432\u044B\u0435 \u0442\u0440\u0435\u0431\u043E\u0432\u0430\u043D\u0438\u044F, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u043F\u043E\u0442\u0440\u0435\u0431\u0443\u044E\u0442 \u0438\u0437\u043C\u0435\u043D\u0438\u0442\u044C \u0444\u043E\u0440\u043C\u0430\u0442 \u0434\u0430\u043D\u043D\u044B\u0445 \u0438\u043B\u0438 \u0434\u043E\u0431\u0430\u0432\u0438\u0442\u044C \u043E\u0431\u044F\u0437\u0430\u0442\u0435\u043B\u044C\u043D\u044B\u0435 \u043F\u043E\u043B\u044F. \u0411\u0435\u0437 \u0432\u0435\u0440\u0441\u0438\u043E\u043D\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u044F \u043A\u0430\u0436\u0434\u043E\u0435 \u0442\u0430\u043A\u043E\u0435 \u0438\u0437\u043C\u0435\u043D\u0435\u043D\u0438\u0435 \u0441\u043B\u043E\u043C\u0430\u0435\u0442 \u043A\u043B\u0438\u0435\u043D\u0442\u043E\u0432, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0443\u0436\u0435 \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u044E\u0442 API.","permalink":"/sysanalyst-kb.github.io/docs/integration/api-versioning"},{"id":"integration/api-openapi","title":"\u0414\u043E\u043A\u0443\u043C\u0435\u043D\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u0435 API \u0441\u043E \u0441\u043F\u0435\u0446\u0438\u0444\u0438\u043A\u0430\u0446\u0438\u0435\u0439 OpenAPI","description":"OpenAPI (\u0440\u0430\u043D\u0435\u0435 \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u044B\u0439 \u043A\u0430\u043A Swagger) \u2014 \u044D\u0442\u043E \u0441\u0442\u0430\u043D\u0434\u0430\u0440\u0442 \u043E\u043F\u0438\u0441\u0430\u043D\u0438\u044F REST API \u0432 \u0444\u043E\u0440\u043C\u0430\u0442\u0435 YAML \u0438\u043B\u0438 JSON. \u0421\u043F\u0435\u0446\u0438\u0444\u0438\u043A\u0430\u0446\u0438\u044F OpenAPI \u043F\u043E\u0437\u0432\u043E\u043B\u044F\u0435\u0442 \u043E\u043F\u0438\u0441\u0430\u0442\u044C \u0432\u0441\u0435 \u044D\u043D\u0434\u043F\u043E\u0438\u043D\u0442\u044B, \u0444\u043E\u0440\u043C\u0430\u0442\u044B \u0434\u0430\u043D\u043D\u044B\u0445, \u043F\u0430\u0440\u0430\u043C\u0435\u0442\u0440\u044B \u0438 \u0441\u043F\u043E\u0441\u043E\u0431\u044B \u0430\u0443\u0442\u0435\u043D\u0442\u0438\u0444\u0438\u043A\u0430\u0446\u0438\u0438.","permalink":"/sysanalyst-kb.github.io/docs/integration/api-openapi"},{"id":"specialization/logistics-integrations","title":"\u0418\u043D\u0442\u0435\u0433\u0440\u0430\u0446\u0438\u0438 \u0441 \u043C\u0430\u0440\u043A\u0435\u0442\u043F\u043B\u0435\u0439\u0441\u0430\u043C\u0438 \u0438 \u043A\u0443\u0440\u044C\u0435\u0440\u0430\u043C\u0438","description":"\u041B\u043E\u0433\u0438\u0441\u0442\u0438\u0447\u0435\u0441\u043A\u0430\u044F \u043F\u043B\u0430\u0442\u0444\u043E\u0440\u043C\u0430 \u0438\u043D\u0442\u0435\u0433\u0440\u0438\u0440\u0443\u0435\u0442\u0441\u044F \u0441 \u0434\u0435\u0441\u044F\u0442\u043A\u0430\u043C\u0438 \u0432\u043D\u0435\u0448\u043D\u0438\u0445 \u0441\u0435\u0440\u0432\u0438\u0441\u043E\u0432 \u0430\u0441\u0438\u043D\u0445\u0440\u043E\u043D\u043D\u043E\u0441\u0442\u044C (Webhook + Polling), \u043E\u0431\u0440\u0430\u0431\u043E\u0442\u043A\u0430 \u043E\u0448\u0438\u0431\u043E\u043A, \u0440\u0435\u0442\u0440\u0430\u0438, \u0438\u0434\u0435\u043C\u043F\u043E\u0442\u0435\u043D\u0442\u043D\u043E\u0441\u0442\u044C.","permalink":"/sysanalyst-kb.github.io/docs/specialization/logistics-integrations"},{"id":"integration/api-rest-basics","title":"\u041E\u0441\u043D\u043E\u0432\u044B REST API","description":"REST (Representational State Transfer) \u2014 \u044D\u0442\u043E \u0430\u0440\u0445\u0438\u0442\u0435\u043A\u0442\u0443\u0440\u043D\u044B\u0439 \u0441\u0442\u0438\u043B\u044C \u043F\u0440\u043E\u0435\u043A\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u044F \u0440\u0430\u0441\u043F\u0440\u0435\u0434\u0435\u043B\u0451\u043D\u043D\u044B\u0445 \u0441\u0438\u0441\u0442\u0435\u043C, \u043F\u0440\u0435\u0434\u043B\u043E\u0436\u0435\u043D\u043D\u044B\u0439 \u0420\u043E\u0435\u043C \u0424\u0438\u043B\u0434\u0438\u043D\u0433\u043E\u043C \u0432 2000 \u0433\u043E\u0434\u0443. REST API \u0441\u0442\u0430\u043B\u0438 \u0441\u0442\u0430\u043D\u0434\u0430\u0440\u0442\u043E\u043C \u0434\u0435-\u0444\u0430\u043A\u0442\u043E \u0434\u043B\u044F \u0432\u0435\u0431-\u0438\u043D\u0442\u0435\u0433\u0440\u0430\u0446\u0438\u0439.","permalink":"/sysanalyst-kb.github.io/docs/integration/api-rest-basics"},{"id":"specialization/socnet-eco","title":"\u041F\u043B\u0430\u0442\u0444\u043E\u0440\u043C\u0435\u043D\u043D\u044B\u0435 \u043C\u0435\u0445\u0430\u043D\u0438\u043A\u0438 \u2014 API, SDK, \u043C\u0430\u0440\u043A\u0435\u0442\u043F\u043B\u0435\u0439\u0441 \u043F\u0440\u0438\u043B\u043E\u0436\u0435\u043D\u0438\u0439","description":"\u041F\u043B\u0430\u0442\u0444\u043E\u0440\u043C\u0435\u043D\u043D\u044B\u0435 \u043C\u0435\u0445\u0430\u043D\u0438\u043A\u0438 \u2014 Public API \u0438 SDK \u0434\u043B\u044F \u0432\u043D\u0435\u0448\u043D\u0438\u0445 \u0440\u0430\u0437\u0440\u0430\u0431\u043E\u0442\u0447\u0438\u043A\u043E\u0432, \u043C\u0430\u0440\u043A\u0435\u0442\u043F\u043B\u0435\u0439\u0441 \u043F\u0440\u0438\u043B\u043E\u0436\u0435\u043D\u0438\u0439 (\u0431\u043E\u0442\u044B, \u043C\u0438\u043D\u0438-\u0430\u043F\u043F\u044B, \u0438\u0433\u0440\u044B \u0432\u043D\u0443\u0442\u0440\u0438 \u043F\u043B\u0430\u0442\u0444\u043E\u0440\u043C\u044B) \u0438 creator economy (\u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u044B \u0434\u043B\u044F \u0430\u0432\u0442\u043E\u0440\u043E\u0432). \u041F\u0440\u0438\u043C\u0435\u0440\u044B: Telegram Bot API (10M+ \u0431\u043E\u0442\u043E\u0432), WeChat Mini Programs (5M+ \u043F\u0440\u0438\u043B\u043E\u0436\u0435\u043D\u0438\u0439), Discord API (1M+ \u0431\u043E\u0442\u043E\u0432), Facebook Graph API. \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u043F\u0440\u043E\u0435\u043A\u0442\u0438\u0440\u0443\u0435\u0442 API-\u043A\u043E\u043D\u0442\u0440\u0430\u043A\u0442\u044B, SDK, revenue share (70/30), \u043F\u043E\u043B\u0438\u0442\u0438\u043A\u0443 \u043F\u0443\u0431\u043B\u0438\u043A\u0430\u0446\u0438\u0438, rate limiting \u0438 \u043C\u0435\u0442\u0440\u0438\u043A\u0438 \u044D\u043A\u043E\u0441\u0438\u0441\u0442\u0435\u043C\u044B (developer NPS, app quality, ecosystem revenue).","permalink":"/sysanalyst-kb.github.io/docs/specialization/socnet-eco"},{"id":"integration/api-design-detailed","title":"\u041F\u0440\u043E\u0435\u043A\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u0435 REST API \u2014 \u0434\u0435\u0442\u0430\u043B\u044C\u043D\u043E","description":"\u0421\u043F\u0440\u043E\u0435\u043A\u0442\u0438\u0440\u043E\u0432\u0430\u0442\u044C API \u2014 \u0437\u043D\u0430\u0447\u0438\u0442 \u0434\u043E\u0433\u043E\u0432\u043E\u0440\u0438\u0442\u044C\u0441\u044F \u043E \u043A\u043E\u043D\u0442\u0440\u0430\u043A\u0442\u0435 \u043C\u0435\u0436\u0434\u0443 \u0441\u0438\u0441\u0442\u0435\u043C\u0430\u043C\u0438 \u0434\u043E \u0442\u043E\u0433\u043E, \u043A\u0430\u043A \u043D\u0430\u043F\u0438\u0441\u0430\u043D\u0430 \u043F\u0435\u0440\u0432\u0430\u044F \u0441\u0442\u0440\u043E\u043A\u0430 \u043A\u043E\u0434\u0430. \u0425\u043E\u0440\u043E\u0448\u0438\u0439 \u0434\u0438\u0437\u0430\u0439\u043D API \u044D\u043A\u043E\u043D\u043E\u043C\u0438\u0442 \u043D\u0435\u0434\u0435\u043B\u0438 \u043F\u0435\u0440\u0435\u0434\u0435\u043B\u043E\u043A \u0438 \u0434\u0435\u043B\u0430\u0435\u0442 \u0438\u043D\u0442\u0435\u0433\u0440\u0430\u0446\u0438\u044E \u043F\u0440\u0435\u0434\u0441\u043A\u0430\u0437\u0443\u0435\u043C\u043E\u0439.","permalink":"/sysanalyst-kb.github.io/docs/integration/api-design-detailed"},{"id":"specialization/govtech-smev","title":"\u0421\u041C\u042D\u0412 \u2014 \u043C\u0435\u0436\u0432\u0435\u0434\u043E\u043C\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0435 \u044D\u043B\u0435\u043A\u0442\u0440\u043E\u043D\u043D\u043E\u0435 \u0432\u0437\u0430\u0438\u043C\u043E\u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0435","description":"\u0421\u041C\u042D\u0412 \u2014 \xab\u0448\u0438\u043D\u0430\xbb \u0434\u043B\u044F \u043E\u0431\u043C\u0435\u043D\u0430 \u0434\u0430\u043D\u043D\u044B\u043C\u0438 \u043C\u0435\u0436\u0434\u0443 \u0433\u043E\u0441\u0443\u0434\u0430\u0440\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C\u0438 \u0438\u043D\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u043E\u043D\u043D\u044B\u043C\u0438 \u0441\u0438\u0441\u0442\u0435\u043C\u0430\u043C\u0438. \u0412\u0435\u0440\u0441\u0438\u044F 3 (\u0442\u0435\u043A\u0443\u0449\u0430\u044F) \u0440\u0430\u0431\u043E\u0442\u0430\u0435\u0442 \u0447\u0435\u0440\u0435\u0437 REST \u0438 JSON (\u0440\u0430\u043D\u0435\u0435 SOAP/XML). \u0427\u0435\u0440\u0435\u0437 \u0421\u041C\u042D\u0412 \u043F\u0440\u043E\u0445\u043E\u0434\u044F\u0442 1B+ \u0437\u0430\u043F\u0440\u043E\u0441\u043E\u0432/\u0433\u043E\u0434, 25 000+ \u043F\u043E\u0434\u043A\u043B\u044E\u0447\u0451\u043D\u043D\u044B\u0445 \u0413\u0418\u0421. \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u043E\u043F\u0438\u0441\u044B\u0432\u0430\u0435\u0442 5-30 \u0441\u0435\u043A), \u044E\u0440\u0438\u0434\u0438\u0447\u0435\u0441\u043A\u0443\u044E \u0437\u043D\u0430\u0447\u0438\u043C\u043E\u0441\u0442\u044C (\u0423\u041A\u042D\u041F). \u041A\u043B\u044E\u0447\u0435\u0432\u044B\u0435 \u043F\u0440\u043E\u0432\u0430\u0439\u0434\u0435\u0440\u044B: \u0415\u0421\u0418\u0410 (\u0430\u0443\u0442\u0435\u043D\u0442\u0438\u0444\u0438\u043A\u0430\u0446\u0438\u044F + \u043C\u0435\u0442\u0430\u0434\u0430\u043D\u043D\u044B\u0435), \u0448\u043B\u044E\u0437 \u0421\u041C\u042D\u0412 (ViPNet, \u043A\u0440\u0438\u043F\u0442\u043E\u0433\u0440\u0430\u0444\u0438\u044F).","permalink":"/sysanalyst-kb.github.io/docs/specialization/govtech-smev"},{"id":"basics/what-is-api","title":"\u0427\u0442\u043E \u0442\u0430\u043A\u043E\u0435 API","description":"API \u2014 \u044D\u0442\u043E \u043C\u0435\u043D\u044E \u0440\u0435\u0441\u0442\u043E\u0440\u0430\u043D\u0430. \u041E\u043D\u043E \u0433\u043E\u0432\u043E\u0440\u0438\u0442, \u0447\u0442\u043E \u043A\u0443\u0445\u043D\u044F \u0443\u043C\u0435\u0435\u0442 \u0433\u043E\u0442\u043E\u0432\u0438\u0442\u044C, \u043A\u0430\u043A\u0438\u0435 \u0431\u043B\u044E\u0434\u0430 \u0434\u043E\u0441\u0442\u0443\u043F\u043D\u044B \u0438 \u043A\u0430\u043A \u0438\u0445 \u0437\u0430\u043A\u0430\u0437\u044B\u0432\u0430\u0442\u044C. \u0411\u0435\u0437 \u043C\u0435\u043D\u044E \u0432\u044B \u043D\u0435 \u0437\u043D\u0430\u0435\u0442\u0435, \u0447\u0442\u043E \u043C\u043E\u0436\u043D\u043E \u0437\u0430\u043A\u0430\u0437\u0430\u0442\u044C.","permalink":"/sysanalyst-kb.github.io/docs/basics/what-is-api"}],"unlisted":false}}')}}]);